#!/bin/bash
sed -i 's/tasks.register("interrogateCpu", JavaExec) {/tasks.register("interrogateCpuNative", Exec) {\n            group = "cpu-cache"\n            description = "Interrogate CPU cache topology using Native binary and print Confix JSON"\n            \n            def isMac = System.getProperty("os.name") == "Mac OS X"\n            def isArm = System.getProperty("os.arch") == "aarch64"\n            \n            def targetName = "linux"\n            if (isMac) {\n                targetName = isArm ? "macosArm64" : "macosX64"\n            } else if (isArm) {\n                targetName = "linuxArm64"\n            }\n            \n            dependsOn("linkInterrogateNativeReleaseExecutable${targetName.capitalize()}")\n            def buildDir = layout.buildDirectory.get().asFile\n            commandLine("${buildDir}\/bin\/${targetName}\/interrogateNativeReleaseExecutable\/interrogateNative.kexe")\n        }\n        tasks.register("interrogateCpu", JavaExec) {/g' gradle/macros/trikeshed-lib.gradle
